 using Microsoft.EntityFrameworkCore;
 using System.Linq;
 using System.Threading.Tasks;

 class CosmosQuery
 {
     // [EF9 breaking] Cosmos provider no longer supports sync I/O — use async
     async Task FindProducts(ProductContext ctx)
     {
         // Direct Cosmos SQL — safe because we preserved "Discriminator" via HasDiscriminator config
         var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
         var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
     }
 }
